public class Scope {
    static int x = 1;
    public static void main(String[] args) {
        int x = 2;      // shadows static x
        {
            int y = 3;
            System.out.println(x + y);       // local x=2, y=3
        }
        System.out.println(x);              // local x=2
        System.out.println(Scope.x);        // static x=1
    }
}
